int btbl_bitcnt(uint32_t x) {
  /* Knob Variables Declaration Start */
  int nibble_stride = 1;
  /* Knob Variables Declaration End */

  /* 4-bit nibble lookup table: popcount for values 0..15 */
  static const char nibble_lut[16] = {0,1,1,2,1,2,2,3,1,2,2,3,2,3,3,4};

  int cnt = 0;
  int nibble_idx;
  int nibbles_counted = 0;

  for (nibble_idx = 0; nibble_idx < 8; nibble_idx += nibble_stride) {
    cnt += nibble_lut[(x >> (nibble_idx * 4)) & 0xF];
    nibbles_counted++;
  }

  /* Scale estimate when nibbles were skipped */
  if (nibble_stride > 1 && nibbles_counted > 0) {
    cnt = (cnt * 8 + nibbles_counted / 2) / nibbles_counted;
  }

#ifdef LOCAL_RUN
