             nibble_stride, nibbles_counted, 8 - nibbles_counted);
      /* Self-test: compare baseline popcount vs nibble LUT */
      uint32_t test_vals[] = {0x0, 0xF, 0xFF, 0xFFFFFFFF, 0x12345678};
      int num_tests = 5;
      int t;
      fprintf(stderr, "[Nibble LUT Self-Test] stride=%d\n", nibble_stride);
      fprintf(stderr, "  %-12s %-10s %-10s\n", "Input", "Baseline", "Approx");
      for (t = 0; t < num_tests; t++) {
        uint32_t v = test_vals[t];
        /* Reference: Brian Kernighan popcount */
        int baseline = 0;
        uint32_t tmp = v;
        while (tmp) { baseline++; tmp &= (tmp - 1); }
        /* Approximated nibble LUT */
        int approx = 0;
        int nc = 0;
        int ni;
        for (ni = 0; ni < 8; ni += nibble_stride) {
          approx += nibble_lut[(v >> (ni * 4)) & 0xF];
          nc++;
        }
        if (nibble_stride > 1 && nc > 0) {
          approx = (approx * 8 + nc / 2) / nc;
        }
        fprintf(stderr, "  0x%08X  %-10d %-10d\n", v, baseline, approx);
      }
      _nlut_dbg = 1;
    }
  }
#endif

  return cnt;
}
